case "get_executions": {
  const input = z
    .object({
      limit: z.number().min(1).max(100).default(20),
      offset: z.number().min(0).default(0),  // NEW
      status: z.enum(["success", "failure", "running"]).optional(),
      branch: z.string().optional(),
      suite: z.string().optional(),
      from: z.string().optional(),
      to: z.string().optional(),
    })
    .parse(args)

  const executions = await db.getExecutions(
    orgId,
    input.limit,
    input.offset,  // NEW
    input.status,
    input.branch,
    input.from && input.to ? { from: input.from, to: input.to } : undefined,
    input.suite
  )

  return jsonResponse({
    organization: authContext.organizationSlug,
    count: executions.length,
    pagination: {
      offset: input.offset,
      limit: input.limit,
      has_more: executions.length === input.limit,
    },
    executions,
  })
}
